      "speakers": [
        {
          "name": "Manar Yacoub Criner",
          "bio": "I work at the Wikimedia Foundation as a Manager on the Movement Communications team.",
          "url": "https://wikimedia.eventyay.com/wm/wikimania2026/speakers/9ADQPQ/"
        }
      ],
